import{c as t,Q as a,j as i,m as s}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Audio Dedup Report and Cleanup Script","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/audio-dedup.md","filePath":"scripts/audio-dedup.md","lastUpdated":1780026524000}'),d={name:"scripts/audio-dedup.md"};function o(r,e,l,n,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="audio-dedup-report-and-cleanup-script" tabindex="-1">Audio Dedup Report and Cleanup Script <a class="header-anchor" href="#audio-dedup-report-and-cleanup-script" aria-label="Permalink to &quot;Audio Dedup Report and Cleanup Script&quot;">​</a></h1><p>Run this script with the project Python environment when possible:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Duplicate-audio helper with two modes. By default it is report-only: it reads an existing <code>dj-track-similarity</code> SQLite database, compares tracks inside a selected stored path root, and writes JSON, styled XLSX, and text-log reports. The report also checks the default Rhythm Lab database at <code>tools\\rhythm-lab\\data\\rhythm_lab.sqlite</code> and lists any lab rows that would be removed for safe delete candidates. The JSON report stores both a compact <code>rhythm_lab.summary</code> object and the detailed affected rows; the text log writes the same summary as a <code>rhythm_lab_summary=...</code> line. With <code>--apply</code> it adds a confirmed cleanup pass that deletes safe duplicate files and their database rows after the reports are written. If a Rhythm Lab database exists at the default path, apply mode also removes matching lab rows for the deleted source track IDs.</p><p>Use the default report mode when you want evidence for possible duplicate audio before cleaning a library. It is intentionally conservative: it always produces the reports first. The destructive cleanup runs only with <code>--apply</code> and an interactive confirmation prompt, and it deletes only candidates the report marks as safe.</p><p>Usage:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\audio_dedup\\audio_dedup.py --root ROOT [OPTIONS]</span></span></code></pre></div><p>Options:</p><ul><li><code>--db DB</code>: project SQLite database. Default is <code>C:\\db\\abstracted.sqlite</code>.</li><li><code>--root ROOT</code>: required stored path root used to limit candidate tracks.</li><li><code>--path-contains TEXT</code>: additional case-insensitive path filter. Can be repeated.</li><li><code>--preset safe|balanced|aggressive</code>: scoring preset. Default is <code>safe</code>.</li><li><code>--min-score SCORE</code>: override the preset duplicate threshold.</li><li><code>--limit-groups N</code>: write at most N duplicate groups.</li><li><code>--out-dir DIR</code>: output report directory. Default is <code>scripts\\audio_dedup\\reports</code>.</li><li><code>--apply</code>: after reports are written, ask for an exact confirmation phrase and delete only candidates marked <code>DELETE CANDIDATE</code> / <code>true_candidate</code>. Tracks are removed from SQLite only after their audio files are successfully deleted.</li></ul><h2 id="presets" tabindex="-1">Presets <a class="header-anchor" href="#presets" aria-label="Permalink to &quot;Presets&quot;">​</a></h2><p>Each preset sets a default duplicate-score threshold, a stricter direct keeper-match threshold for automatic delete candidates, and how strict the duration match must be. <code>--min-score</code> overrides only the report inclusion score threshold; the safe-delete and duration parameters stay as listed.</p><table tabindex="0"><thead><tr><th>Preset</th><th>Min score</th><th>Safe delete score</th><th>Duration tolerance</th><th>Use when</th></tr></thead><tbody><tr><td><code>safe</code></td><td><code>0.965</code></td><td><code>0.980</code></td><td>~2 s / 1% ratio</td><td>Conservative maintenance with the fewest false positives.</td></tr><tr><td><code>balanced</code></td><td><code>0.950</code></td><td><code>0.980</code></td><td>~5 s / 2.5% ratio</td><td>A wider review net with the same safe-delete confidence as <code>safe</code>.</td></tr><tr><td><code>aggressive</code></td><td><code>0.925</code></td><td><code>0.990</code></td><td>~15 s / 8% ratio</td><td>Broadest matching; expect mostly manual review unless direct evidence is near-identical.</td></tr></tbody></table><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><p>The pair score blends available signals into a single value in <code>0..1</code>, normalized by the weight of the signals that exist for both tracks:</p><table tabindex="0"><thead><tr><th>Signal</th><th>Weight</th></tr></thead><tbody><tr><td>MERT embedding similarity</td><td><code>0.43</code></td></tr><tr><td>MAEST embedding similarity</td><td><code>0.32</code></td></tr><tr><td>SONARA feature similarity</td><td><code>0.14</code></td></tr><tr><td>CLAP embedding similarity</td><td><code>0.04</code></td></tr><tr><td>Duration closeness</td><td><code>0.05</code></td></tr></tbody></table><p>Each group is labelled with a confidence tier of <code>high</code>, <code>medium</code>, or <code>review</code> based on its score and any blocking reasons. Tagged BPM/key values are shown as track metadata only and are never used for duplicate scoring.</p><p>Examples:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">preset balanced </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contains mastered</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">preset safe </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply</span></span></code></pre></div><p>Outputs are named <code>audio_dedup_report_&lt;timestamp&gt;.json</code>, <code>.xlsx</code>, and <code>.log</code>. The default report directory is ignored by git.</p><p>The CLI prints a short terminal summary after each run, including the duplicate group count, safe delete candidate count in report mode, and Rhythm Lab database/affected-row counts.</p><p>The workbook is the main human review artifact. It includes:</p><ul><li><code>Summary</code>: database path, selected root, preset, score threshold, total track count in the database, track count inside the selected root/filter scope, duplicate-group and candidate counts, a confidence breakdown (<code>high</code>/<code>medium</code>/<code>review</code>), and MERT/MAEST/CLAP embedding coverage counts.</li><li><code>Groups</code>: one row per duplicate group, with the suggested <code>KEEP</code> track and the reasons it outranks the other files.</li><li><code>Candidates</code>: one row per duplicate candidate, with <code>DELETE CANDIDATE</code> or <code>REVIEW MANUALLY</code>, the keeper path, direct score, similarity evidence, and review blockers.</li><li><code>Pair Evidence</code>: the detailed pairwise MERT, MAEST, SONARA, CLAP, and duration evidence used by the grouping step. Tagged BPM/key values are shown only as track metadata and are not used for duplicate scoring; SONARA BPM remains part of the SONARA similarity signal when available.</li><li><code>Rhythm Lab</code>: rows in the default Rhythm Lab database that would be removed by apply mode for candidates marked safe to delete. If the database is missing or no safe candidate has lab rows, the sheet contains only headers.</li></ul><p>Review every candidate manually; the report includes suggested keepers and candidate-delete evidence.</p><p>Apply mode:</p><ol><li>The script writes the JSON/XLSX/log reports first.</li><li>It counts safe delete candidates only.</li><li>It prints a destructive-action warning and requires typing exactly <code>APPLY DELETE</code>.</li><li>It deletes only files still inside the selected <code>--root</code>.</li><li>It removes SQLite rows only for tracks whose files were successfully deleted. Related rows in tables with a <code>track_id</code> column are removed before the <code>tracks</code> row.</li><li>It opens <code>tools\\rhythm-lab\\data\\rhythm_lab.sqlite</code>, when it exists, and removes rows whose <code>source_track_id</code> matches the successfully deleted track IDs. This cleans manual labels and predictions without touching classifier profiles or training checkpoints.</li><li>It rewrites the JSON and log reports with <code>mode</code> set to <code>apply</code> and an <code>apply_result</code> block listing deleted track IDs, deleted paths, and any skipped or failed deletions, plus the Rhythm Lab row cleanup count. The log also writes a <code>deleted_files:</code> block with one <code>deleted_file=...</code> line for each file successfully removed from disk. The existing <code>rhythm_lab.summary</code> block remains in the JSON as the pre-apply impact summary that was shown in the workbook.</li></ol><p>If you decline the confirmation, the reports stay on disk and nothing is deleted. Do not use <code>--apply</code> until you have reviewed the generated workbook. Automated tests and routine verification should not invoke the script with <code>--apply</code>.</p><p>Start with the <code>safe</code> preset for normal library maintenance. Use <code>balanced</code> or <code>aggressive</code> only when you are comfortable reviewing more false positives.</p>`,27)])])}const k=t(d,[["render",o]]);export{u as __pageData,k as default};
